import React, { useState, useEffect } from "react";
import Article from "./components/Article";
import styled from "styled-components";
import { PostList } from "./components/PostList";

const Main = styled.main`
  display: grid;
  grid-template-columns: 1fr;
  grid-template-rows: 195px 75px 1fr;
`;
const ImgTitle = styled.div`
  margin-bottom: 25px;
  background-image: url(https://images.pexels.com/photos/1415994/pexels-photo-1415994.jpeg?auto=compress&cs=tinysrgb&dpr=2&h=750&w=1260);
  background-position: center;
  background-size: cover;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  color: #fff;
`;
const Ads = styled.div`
  background-image: url(https://c.pxhere.com/images/5a/32/c4e883fc545a190cb62a742009fb-1445331.jpg!d);
  background-position: center;
  background-size: cover;
`;
const Posts = styled.div`
  display: grid;
  grid-template-columns: 1fr;
  grid-template-rows: 42px;
  grid-auto-flow: rows;
  grid-auto-rows: minmax(150px, 1fr);
  background-color: #fff;
  & > span {
    display: flex;
    align-items: center;
    padding-left: 20px;
    background-color: #f4f4f4;
  }
`;

interface PostListType {
  category: string;
  seq: number;
  content: () => any;
}
function Home({ history }: any) {
  const [postList, setPostList] = useState<PostListType[] | undefined>();
  useEffect(() => {
    PostList.sort(function(a, b) {
      if (a.seq < b.seq) {
        return 1;
      }
      if (a.seq > b.seq) {
        return -1;
      }
      // a must be equal to b
      return 0;
    });

    setPostList(PostList);
  }, []);

  const goPath = (url: string) => {
    history.push(url);
  };
  if (!postList) {
    return null;
  }
  return (
    <Main>
      <ImgTitle>
        <h3>Dryad 블로그</h3>
        <p>세상 사람들이 편해지는 기술</p>
      </ImgTitle>
      <Ads></Ads>
      <Posts>
        <span>최근 글</span>
        {postList.map(post => (
          <Article key={post.seq} {...post} goPath={goPath} />
        ))}
      </Posts>
    </Main>
  );
}

export default Home;
